#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
using namespace std;
const int N=1e7+10;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
bool vis[N];int pm[N],mu[N],s[N],cnt;
inline void Init(int mx)
{
	vis[1]=1;mu[1]=1;rep(2,mx,i)
	{
		if(!vis[i])mu[pm[++cnt]=i]=-1;
		rep(1,cnt,j)
		{
			if(pm[j]*i>mx)break;
			mu[pm[j]*i]=(i%pm[j]==0)?0:-mu[i];
			vis[pm[j]*i]=1;if(i%pm[j]==0)break;
		}
	}
	rep(1,cnt,i){int j=1;while(pm[i]*j<=mx)s[pm[i]*j]+=mu[j],j++;}
	rep(1,mx,i)s[i]+=s[i-1];return;
}
inline void Solve()
{
	int n=read(),m=read();long long ans=0;
	for(int l=1,r=0;l<=min(n,m);l=r+1)
	{
		r=min(n/(n/l),m/(m/l));
		ans+=1ll*(n/l)*(m/l)*(s[r]-s[l-1]);
	}
	printf("%lld\n",ans);return;
}
int main(){int T=read();Init(N-1);while(T--)Solve();return 0;}
